/*
 * egtm_atom_3_phase_inverter_pwm.c
 *
 * Production driver: EGTM ATOM 3-Phase Inverter PWM (TC4xx)
 * - Unified IfxEgtm_Pwm driver
 * - Complementary, center-aligned PWM
 * - 3 logical channels (U, V, W) with dead-time and sync start/update
 *
 * Notes:
 * - No watchdog API calls here (must be in CpuX_Main.c only).
 * - No STM/timing logic here (handled by application loop).
 * - Pin routing is handled via IfxEgtm_Pwm_OutputConfig; no PinMap_set calls.
 */

#include "egtm_atom_3_phase_inverter_pwm.h"

#include "Ifx_Types.h"
#include "IfxEgtm_Pwm.h"
#include "IfxPort.h"
#include "IfxPort_Pinmap.h"

/* =============================
 * Configuration Macros
 * ============================= */
#define NUM_OF_CHANNELS            (3u)
#define PWM_FREQUENCY              (20000.0f)   /* 20 kHz */
#define ISR_PRIORITY_ATOM          (20)

#define PHASE_U_DUTY               (25.0f)
#define PHASE_V_DUTY               (50.0f)
#define PHASE_W_DUTY               (75.0f)

/* Duty ramp step (percent). Application-chosen; periodic scheduling done in CpuX_Main. */
#define PHASE_DUTY_STEP            (5.0f)

/* Validated EGTM ATOM TOUT pins (use only validated symbols). */
#define PHASE_U_HS                 (&IfxEgtm_ATOM0_0_TOUT0_P02_0_OUT)
#define PHASE_U_LS                 (&IfxEgtm_ATOM0_0N_TOUT1_P02_1_OUT)
/* Board validation pending for remaining phases; placeholders provided. */
#define PHASE_V_HS                 (NULL_PTR) /* Replace with &IfxEgtm_ATOMx_y_TOUTz_Pxx_y_OUT after board pin validation */
#define PHASE_V_LS                 (NULL_PTR) /* Replace with &IfxEgtm_ATOMx_yN_TOUTz_Pxx_y_OUT after board pin validation */
#define PHASE_W_HS                 (NULL_PTR) /* Replace with &IfxEgtm_ATOMx_y_TOUTz_Pxx_y_OUT after board pin validation */
#define PHASE_W_LS                 (NULL_PTR) /* Replace with &IfxEgtm_ATOMx_yN_TOUTz_Pxx_y_OUT after board pin validation */

/* Debug LED: port/pin compound macro (Port 13.0 as example). */
#define LED                        &MODULE_P13, 0

/* =============================
 * Module State
 * ============================= */

typedef struct
{
    IfxEgtm_Pwm            pwm;                               /* Driver handle */
    IfxEgtm_Pwm_Channel    channels[NUM_OF_CHANNELS];         /* Channel objects (persistent) */
    float32                dutyCycles[NUM_OF_CHANNELS];        /* Percent duty [0..100] */
    float32                phases[NUM_OF_CHANNELS];            /* Phase offset in degrees/percent (reserved) */
    IfxEgtm_Pwm_DeadTime   deadTimes[NUM_OF_CHANNELS];         /* Stored dead-times for each channel */
} EgtmAtom3phInv_State;

IFX_STATIC EgtmAtom3phInv_State g_egtmAtom3phInv;

/* =============================
 * ISR and Callback
 * ============================= */

/* Period-event callback: MUST be empty by design. */
void IfxEgtm_periodEventFunction(void *data)
{
    (void)data;
}

/* ISR declaration and definition: toggle LED only. */
IFX_INTERRUPT(interruptEgtmAtom, 0, ISR_PRIORITY_ATOM);
void interruptEgtmAtom(void)
{
    IfxPort_togglePin(LED);
}

/* =============================
 * Public Functions
 * ============================= */

/**
 * Initialize a 3-phase inverter PWM using eGTM ATOM with unified IfxEgtm_Pwm.
 * - Declares local config structures (main, per-channel, DTM, interrupt, output).
 * - Sets complementary HS/LS outputs, center-aligned 20 kHz PWM, ~1 us dead-time.
 * - Enables syncStart and syncUpdate.
 * - Performs EGTM module enable guard and CMU clock configuration.
 * - Initializes driver with persistent handle and channels array.
 * - Stores initial duty and dead-time into module state.
 * - Configures a debug LED GPIO; ISR toggles LED on PWM period.
 */
void initEgtmAtom3phInv(void)
{
    /* 1) Declare configuration structures (locals) */
    IfxEgtm_Pwm_Config           config;
    IfxEgtm_Pwm_ChannelConfig    channelConfig[NUM_OF_CHANNELS];
    IfxEgtm_Pwm_DtmConfig        dtmConfig[NUM_OF_CHANNELS];
    IfxEgtm_Pwm_InterruptConfig  irqCfg;
    IfxEgtm_Pwm_OutputConfig     output[NUM_OF_CHANNELS];

    /* 2) Load defaults */
    IfxEgtm_Pwm_initConfig(&config, &MODULE_EGTM);

    /* 3) Output configuration (HS/LS complementary pairs) */
    /* Phase U */
    output[0].pin                   = (IfxEgtm_Pwm_ToutMap *)PHASE_U_HS;
    output[0].complementaryPin      = (IfxEgtm_Pwm_ToutMap *)PHASE_U_LS;
    output[0].polarity              = Ifx_ActiveState_high; /* HS active HIGH */
    output[0].complementaryPolarity = Ifx_ActiveState_low;  /* LS active LOW  */
    output[0].outputMode            = IfxPort_OutputMode_pushPull;
    output[0].padDriver             = IfxPort_PadDriver_cmosAutomotiveSpeed1;

    /* Phase V */
    output[1].pin                   = (IfxEgtm_Pwm_ToutMap *)PHASE_V_HS;
    output[1].complementaryPin      = (IfxEgtm_Pwm_ToutMap *)PHASE_V_LS;
    output[1].polarity              = Ifx_ActiveState_high;
    output[1].complementaryPolarity = Ifx_ActiveState_low;
    output[1].outputMode            = IfxPort_OutputMode_pushPull;
    output[1].padDriver             = IfxPort_PadDriver_cmosAutomotiveSpeed1;

    /* Phase W */
    output[2].pin                   = (IfxEgtm_Pwm_ToutMap *)PHASE_W_HS;
    output[2].complementaryPin      = (IfxEgtm_Pwm_ToutMap *)PHASE_W_LS;
    output[2].polarity              = Ifx_ActiveState_high;
    output[2].complementaryPolarity = Ifx_ActiveState_low;
    output[2].outputMode            = IfxPort_OutputMode_pushPull;
    output[2].padDriver             = IfxPort_PadDriver_cmosAutomotiveSpeed1;

    /* 4) Dead-time (DTM) configuration: 1 us rising/falling for all channels */
    dtmConfig[0].deadTime.rising = 1e-6f; dtmConfig[0].deadTime.falling = 1e-6f; dtmConfig[0].fastShutOff = NULL_PTR;
    dtmConfig[1].deadTime.rising = 1e-6f; dtmConfig[1].deadTime.falling = 1e-6f; dtmConfig[1].fastShutOff = NULL_PTR;
    dtmConfig[2].deadTime.rising = 1e-6f; dtmConfig[2].deadTime.falling = 1e-6f; dtmConfig[2].fastShutOff = NULL_PTR;

    /* 5) Interrupt configuration: pulse notify on period event, CPU0 provider */
    irqCfg.mode        = IfxEgtm_IrqMode_pulseNotify;
    irqCfg.isrProvider = IfxSrc_Tos_cpu0;
    irqCfg.priority    = ISR_PRIORITY_ATOM;
    irqCfg.vmId        = IfxSrc_VmId_0;
    irqCfg.periodEvent = IfxEgtm_periodEventFunction;
    irqCfg.dutyEvent   = NULL_PTR;

    /* 6) Channel configuration (logical indices 0..2) */
    /* Channel 0 -> Phase U */
    channelConfig[0].timerCh   = IfxEgtm_Pwm_SubModule_Ch_0;
    channelConfig[0].phase     = 0.0f;
    channelConfig[0].duty      = PHASE_U_DUTY;
    channelConfig[0].dtm       = &dtmConfig[0];
    channelConfig[0].output    = &output[0];
    channelConfig[0].mscOut    = NULL_PTR;               /* not using MSC connection */
    channelConfig[0].interrupt = &irqCfg;                /* base channel gets interrupt */

    /* Channel 1 -> Phase V */
    channelConfig[1].timerCh   = IfxEgtm_Pwm_SubModule_Ch_1;
    channelConfig[1].phase     = 0.0f;
    channelConfig[1].duty      = PHASE_V_DUTY;
    channelConfig[1].dtm       = &dtmConfig[1];
    channelConfig[1].output    = &output[1];
    channelConfig[1].mscOut    = NULL_PTR;
    channelConfig[1].interrupt = NULL_PTR;               /* only base channel has interrupt */

    /* Channel 2 -> Phase W */
    channelConfig[2].timerCh   = IfxEgtm_Pwm_SubModule_Ch_2;
    channelConfig[2].phase     = 0.0f;
    channelConfig[2].duty      = PHASE_W_DUTY;
    channelConfig[2].dtm       = &dtmConfig[2];
    channelConfig[2].output    = &output[2];
    channelConfig[2].mscOut    = NULL_PTR;
    channelConfig[2].interrupt = NULL_PTR;

    /* 7) Main configuration */
    config.cluster             = IfxEgtm_Cluster_0;                      /* Match ATOM0 */
    config.subModule           = IfxEgtm_Pwm_SubModule_atom;             /* Use ATOM submodule */
    config.alignment           = IfxEgtm_Pwm_Alignment_center;           /* Center-aligned */
    config.numChannels         = NUM_OF_CHANNELS;
    config.channels            = channelConfig;
    config.frequency           = PWM_FREQUENCY;                           /* 20 kHz */
    config.clockSource.atom    = IfxEgtm_Cmu_Fxclk_0;                     /* ATOM clock source */
    config.dtmClockSource      = IfxEgtm_Dtm_ClockSource_systemClock;     /* DTM clock source */
    config.syncUpdateEnabled   = TRUE;                                    /* Latch updates on period */
    config.syncStart           = TRUE;                                    /* Start channels synchronously */

    /* 8) Enable guard: enable EGTM and configure CMU clocks (inside guard only) */
    if (!IfxEgtm_isEnabled(&MODULE_EGTM))
    {
        IfxEgtm_enable(&MODULE_EGTM);
        float32 freq = IfxEgtm_Cmu_getModuleFrequency(&MODULE_EGTM);
        /* Set global and channel clocks to module frequency */
        IfxEgtm_Cmu_setGclkFrequency(&MODULE_EGTM, freq);
        IfxEgtm_Cmu_setClkFrequency(&MODULE_EGTM, IfxEgtm_Cmu_Clk_0, freq);
        /* Additionally enforce 1:1 dividers per migration requirement */
        IfxEgtm_Cmu_setGclkDivider(&MODULE_EGTM, 1u, 1u);
        IfxEgtm_Cmu_setEclkDivider(&MODULE_EGTM, IfxEgtm_Cmu_Eclk_0, 1u, 1u);
        /* Enable FXCLK and CLK0 as needed by ATOM */
        IfxEgtm_Cmu_enableClocks(&MODULE_EGTM, (uint32)(IFXEGTM_CMU_CLKEN_FXCLK | IFXEGTM_CMU_CLKEN_CLK0));
    }

    /* 9) Initialize PWM driver with persistent handle and channels array */
    IfxEgtm_Pwm_init(&g_egtmAtom3phInv.pwm, g_egtmAtom3phInv.channels, &config);

    /* 10) Store initial duties and dead-times in the persistent state */
    g_egtmAtom3phInv.dutyCycles[0] = PHASE_U_DUTY;
    g_egtmAtom3phInv.dutyCycles[1] = PHASE_V_DUTY;
    g_egtmAtom3phInv.dutyCycles[2] = PHASE_W_DUTY;

    g_egtmAtom3phInv.phases[0] = 0.0f;
    g_egtmAtom3phInv.phases[1] = 0.0f;
    g_egtmAtom3phInv.phases[2] = 0.0f;

    g_egtmAtom3phInv.deadTimes[0] = dtmConfig[0].deadTime;
    g_egtmAtom3phInv.deadTimes[1] = dtmConfig[1].deadTime;
    g_egtmAtom3phInv.deadTimes[2] = dtmConfig[2].deadTime;

    /* 11) Configure debug LED as output (toggled in ISR) */
    IfxPort_setPinModeOutput(LED, IfxPort_OutputMode_pushPull, IfxPort_OutputIdx_general);
}

/**
 * Duty update: percent-based ramp on U/V/W.
 * - Wrap to 0 if adding step reaches/exceeds 100, then always add step.
 * - Apply atomically via immediate update API (latched by driver-defined event).
 */
void updateEgtmAtom3phInvDuty(void)
{
    if ((g_egtmAtom3phInv.dutyCycles[0] + PHASE_DUTY_STEP) >= 100.0f) { g_egtmAtom3phInv.dutyCycles[0] = 0.0f; }
    if ((g_egtmAtom3phInv.dutyCycles[1] + PHASE_DUTY_STEP) >= 100.0f) { g_egtmAtom3phInv.dutyCycles[1] = 0.0f; }
    if ((g_egtmAtom3phInv.dutyCycles[2] + PHASE_DUTY_STEP) >= 100.0f) { g_egtmAtom3phInv.dutyCycles[2] = 0.0f; }

    g_egtmAtom3phInv.dutyCycles[0] += PHASE_DUTY_STEP;
    g_egtmAtom3phInv.dutyCycles[1] += PHASE_DUTY_STEP;
    g_egtmAtom3phInv.dutyCycles[2] += PHASE_DUTY_STEP;

    IfxEgtm_Pwm_updateChannelsDutyImmediate(&g_egtmAtom3phInv.pwm, (float32 *)g_egtmAtom3phInv.dutyCycles);
}
